parameters.jsonBody:
={
  "model": "mistralai/mistral-7b-instruct:free",
  "temperature": 0.1,
  "max_tokens": 800,
  "response_format": { "type": "json_object" },
  "messages": [
    {
      "role": "system",
      "content": "You are a senior cloud security engineer and infrastructure automation expert. Given a confirmed cloud security finding, generate a concrete remediation package. Return ONLY valid JSON with exactly these fields:
{
  "immediate_fix_cli": "The exact AWS CLI command(s) to fix this right now. Use placeholders like <BUCKET_NAME> where specifics are unknown.",
  "terraform_snippet": "A Terraform resource block or data source that prevents this issue via IaC. Well-formatted HCL.",
  "estimated_fix_minutes": <integer>,
  "production_risk": "low" | "medium" | "high",
  "production_risk_reason": "One sentence on why applying this fix could impact production.",
  "verification_command": "AWS CLI command to verify the fix was applied correctly.",
  "remediation_summary": "2-3 sentences describing what to do and why."}

Be precise and production-aware. Never suggest risky changes without noting the risk."
    },
    {
      "role": "user",
      "content": "Generate remediation for this confirmed cloud security finding:

Title: {{ $json.title }}
Source: {{ $json.source }}
Description: {{ $json.description }}
Resource ID: {{ $json.resource_id }}
Resource Type: {{ $json.resource_type }}
Cloud Account: {{ $json.cloud_account }}
Region: {{ $json.region }}
Environment: {{ $json.env_tag || 'unknown' }}
Risk Score: {{ $json.risk_score }}/10
MITRE TTPs: {{ $json.mitre_ttp_ids || 'N/A' }}
AI Triage Rationale: {{ $json.triage_rationale }}"
    }
  ]
}

parameters.jsCode:
const raw = $input.first().json;
const alert = $('Filter — Needs Remediation').first().json;

let rem = {};
try {
  const content = raw.choices?.[0]?.message?.content || '{}';
  rem = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch(e) {
  rem = {
    immediate_fix_cli: '# Remediation generation failed — manual review required',
    terraform_snippet: '# Terraform snippet unavailable',
    estimated_fix_minutes: 60,
    production_risk: 'high',
    production_risk_reason: 'Could not assess automatically.',
    verification_command: '# Manual verification required',
    remediation_summary: 'Automated remediation generation failed. Please review manually.'
  };
}

return [{ json: {
  ...alert,
  remediation_summary:       rem.remediation_summary || '',
  immediate_fix_cli:         rem.immediate_fix_cli || '',
  terraform_snippet:         rem.terraform_snippet || '',
  estimated_fix_minutes:     rem.estimated_fix_minutes || 60,
  production_risk:           rem.production_risk || 'medium',
  production_risk_reason:    rem.production_risk_reason || '',
  verification_command:      rem.verification_command || '',
  remediation_generated:     new Date().toISOString(),
  remediation_model:         'mistralai/mistral-7b-instruct:free'
}}];

